{
  "name": "AI Storyboard Director",
  "description": "A professional AI-powered tool for storyboard artists to transform rough sketches into high-fidelity visuals using color masking and reference-based generation.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface ReferenceSlot {
  id: string;
  color: string;
  name: string;
  type: string;
  image?: string;
  confidence?: number;
}

export interface StoryboardLayer {
  id: string;
  name: string;
  type: 'mask' | 'base';
  visible: boolean;
  locked: boolean;
  active?: boolean;
}

export interface ProjectInfo {
  date: string;
  resolution: string;
  description: string;
}

import { GoogleGenAI } from "@google/genai";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const generateDirectorImage = async (
  baseImageBase64: string,
  maskImageBase64: string,
  prompt: string,
  references: { color: string, type: string, image: string }[]
): Promise<string[]> => {
  const ai = getAIClient();

  // Construct a sophisticated prompt for the "Director-Centric AI"
  const referenceContext = references.map(ref => 
    `The area marked with ${ref.color} in the mask corresponds to ${ref.type}. Refer to the provided reference image for this object's design and identity.`
  ).join('\n');

  const finalPrompt = `
    TASK: Transform this storyboard sketch into a high-quality finished cinematic image.
    LOCATE: Maintain the composition, framing, and perspective of the original sketch.
    ASSIGN: 
    ${referenceContext}
    STYLE: Neo-Noir Oil Painting style. Rich textures, dramatic lighting, and deep shadows.
    STORY CONTEXT: ${prompt}

    The output should be a single high-fidelity image that strictly follows these layout and design constraints.
  `;

  // For this implementation, we use gemini-2.5-flash-image which supports image editing/generation
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: baseImageBase64.split(',')[1], mimeType: 'image/png' } },
          { inlineData: { data: maskImageBase64.split(',')[1], mimeType: 'image/png' } },
          // Include reference images if they exist
          ...references.map(ref => ({ inlineData: { data: ref.image.split(',')[1], mimeType: 'image/png' } })),
          { text: finalPrompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    const results: string[] = [];
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          results.push(`data:image/png;base64,${part.inlineData.data}`);
        }
      }
    }

    return results;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { StoryboardLayer, ReferenceSlot, ProjectInfo } from './types';
import { generateDirectorImage } from './services/geminiService';

const DEFAULT_SLOTS: ReferenceSlot[] = [
  { id: 'A', color: 'rgb(239, 68, 68)', name: '슬롯 A (빨강)', type: '캐릭터 얼굴', image: 'https://picsum.photos/400/400?random=1', confidence: 88 },
  { id: 'B', color: 'rgb(59, 130, 246)', name: '슬롯 B (파랑)', type: '환경 소품' },
  { id: 'C', color: 'rgb(234, 179, 8)', name: '슬롯 C (노랑)', type: '추가 요소' },
];

const INITIAL_LAYERS: StoryboardLayer[] = [
  { id: 'l1', name: '컬러 마스크 레이어', type: 'mask', visible: true, locked: false, active: true },
  { id: 'l2', name: '기본 스토리보드', type: 'base', visible: true, locked: true },
];

const App: React.FC = () => {
  const [projectInfo] = useState<ProjectInfo>({
    date: '2024.05.20',
    resolution: '1920 x 1080',
    description: '',
  });
  const [description, setDescription] = useState('');
  const [layers, setLayers] = useState<StoryboardLayer[]>(INITIAL_LAYERS);
  const [slots, setSlots] = useState<ReferenceSlot[]>(DEFAULT_SLOTS);
  const [activeColor, setActiveColor] = useState(DEFAULT_SLOTS[0].color);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const bgImageRef = useRef<HTMLImageElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Setup canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = 20;
  }, []);

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.strokeStyle = activeColor;
    setIsDrawing(true);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const endDrawing = () => {
    setIsDrawing(false);
  };

  const handleGenerate = async () => {
    if (isGenerating) return;
    setIsGenerating(true);

    try {
      const canvas = canvasRef.current;
      const bgImg = bgImageRef.current;
      if (!canvas || !bgImg) return;

      // Prepare images
      // In a real app, we'd capture the base image and the mask separately.
      const maskData = canvas.toDataURL('image/png');

      // Simulate base image from current view or uploaded file
      const baseData = bgImg.src;

      const activeRefs = slots
        .filter(s => s.image)
        .map(s => ({ color: s.color, type: s.type, image: s.image! }));

      const results = await generateDirectorImage(baseData, maskData, description, activeRefs);
      setGeneratedImages(results);
    } catch (err) {
      alert("Failed to generate image. Please check console for details.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSlotUpload = (id: string) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setSlots(prev => prev.map(s => s.id === id ? { ...s, image: base64 } : s));
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#191919]">
      {/* Header */}
      <header className="flex items-center justify-between px-6 py-3 border-b border-[#3b3f54] bg-[#1c1d27]/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-4">
          <div className="w-8 h-8 text-[#f7f7f7]">
            <svg fill="none" viewBox="0 0 48 48" xmlns="http://www.w3.org/2000/svg">
              <path d="M36.7273 44C33.9891 44 31.6043 39.8386 30.3636 33.69C29.123 39.8386 26.7382 44 24 44C21.2618 44 18.877 39.8386 17.6364 33.69C16.3957 39.8386 14.0109 44 11.2727 44C7.25611 44 4 35.0457 4 24C4 12.9543 7.25611 4 11.2727 4C14.0109 4 16.3957 8.16144 17.6364 14.31C18.877 8.16144 21.2618 4 24 4C26.7382 4 29.123 8.16144 30.3636 14.31C31.6043 8.16144 33.9891 4 36.7273 4C40.7439 4 44 12.9543 44 24C44 35.0457 40.7439 44 36.7273 44Z" fill="#2563eb" />
            </svg>
          </div>
          <div className="flex flex-col">
            <h2 className="text-white text-base font-bold leading-tight tracking-tight">AI 스튜디오</h2>
            <p className="text-[#9da1b9] text-xs font-normal">프로젝트 알파 / 장면 01</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2 bg-[#1c1d27]/50 px-3 py-1 rounded-full border border-[#3b3f54]">
            <span className="material-symbols-outlined text-sm text-green-400">verified_user</span>
            <span className="text-[10px] uppercase tracking-widest font-bold text-white">저작권 보호 활성</span>
          </div>
          <div className="flex gap-2">
            <button className="flex items-center justify-center rounded-lg h-9 px-4 bg-[#2563eb] text-white text-sm font-bold transition-all hover:opacity-90">
              프로젝트 저장
            </button>
            <button className="flex items-center justify-center rounded-lg h-9 px-4 bg-[#1c1d27] text-white text-sm font-bold border border-[#3b3f54] transition-all hover:bg-[#3b3f54]">
              내보내기
            </button>
          </div>
          <div className="w-9 h-9 rounded-full border-2 border-blue-500/40 bg-cover" style={{ backgroundImage: `url('https://picsum.photos/100/100?u=1')` }} />
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">
        {/* Left Sidebar */}
        <aside className="w-80 border-r border-[#3b3f54] bg-[#191919] flex flex-col overflow-y-auto">
          <div className="p-4 space-y-6">
            <section>
              <div className="flex items-center gap-2 mb-3">
                <span className="material-symbols-outlined text-blue-500 text-lg">info</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">프로젝트 정보</h3>
              </div>
              <div className="bg-[#1c1d27] border border-[#3b3f54] rounded-lg p-3 space-y-2">
                <div className="flex justify-between items-center text-xs">
                  <span className="text-[#9da1b9]">생성 일자</span>
                  <span className="text-white">{projectInfo.date}</span>
                </div>
                <div className="flex justify-between items-center text-xs">
                  <span className="text-[#9da1b9]">해상도</span>
                  <span className="text-white">{projectInfo.resolution}</span>
                </div>
              </div>
            </section>

            <section>
              <div className="flex items-center gap-2 mb-3">
                <span className="material-symbols-outlined text-blue-500 text-lg">auto_awesome</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">장면 설명</h3>
              </div>
              <div className="relative group">
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="w-full bg-[#1c1d27] border border-[#3b3f54] rounded-lg p-3 text-sm text-white placeholder:text-[#555a77] focus:ring-1 focus:ring-blue-500 focus:border-blue-500 min-h-[120px] resize-none outline-none"
                  placeholder="장면의 캐릭터, 움직임, 조명 등을 설명해주세요..."
                />
                <div className="absolute bottom-3 right-3 flex gap-2">
                  <button className="text-[#9da1b9] hover:text-white transition-colors">
                    <span className="material-symbols-outlined text-lg">mic</span>
                  </button>
                  <button className="text-[#9da1b9] hover:text-white transition-colors">
                    <span className="material-symbols-outlined text-lg">history</span>
                  </button>
                </div>
              </div>
            </section>

            <section>
              <div className="flex items-center justify-between mb-3 px-1">
                <div className="flex items-center gap-2">
                  <span className="material-symbols-outlined text-blue-500 text-lg">layers</span>
                  <h3 className="text-white text-sm font-bold uppercase tracking-wider">레이어 관리</h3>
                </div>
                <button className="text-[#9da1b9] hover:text-white">
                  <span className="material-symbols-outlined text-lg">add_box</span>
                </button>
              </div>
              <div className="space-y-1">
                {layers.map(layer => (
                  <div key={layer.id} className={`flex items-center gap-3 p-2 rounded-lg group ${layer.active ? 'bg-blue-500/10 border border-blue-500/30' : 'bg-[#1c1d27]/30 border border-transparent hover:border-[#3b3f54]'}`}>
                    <span className="material-symbols-outlined text-[#555a77] text-sm cursor-grab">drag_indicator</span>
                    <div className="w-10 h-10 rounded border border-[#3b3f54] flex items-center justify-center overflow-hidden bg-[#1c1d27]">
                      {layer.type === 'mask' ? (
                        <div className="bg-red-500 w-4 h-4 rounded-full" />
                      ) : (
                        <div className="w-full h-full bg-cover bg-center" style={{ backgroundImage: `url('https://picsum.photos/100/100?random=10')` }} />
                      )}
                    </div>
                    <div className="flex-1 overflow-hidden">
                      <p className={`text-xs font-bold truncate ${layer.active ? 'text-white' : 'text-[#9da1b9]'}`}>{layer.name}</p>
                      <p className="text-[10px] text-[#555a77]">{layer.type === 'mask' ? '3개 활성 영역' : 'Procreate에서 가져옴'}</p>
                    </div>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <span className="material-symbols-outlined text-sm cursor-pointer text-[#9da1b9]">{layer.visible ? 'visibility' : 'visibility_off'}</span>
                      <span className="material-symbols-outlined text-sm cursor-pointer text-[#9da1b9]">{layer.locked ? 'lock' : 'lock_open'}</span>
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 bg-[#191919] flex flex-col relative">
          <div className="absolute top-2 left-6 z-40">
            <h1 className="text-[#555a77] text-xs font-bold uppercase tracking-widest mt-4">디렉팅 캔버스</h1>
          </div>

          {/* Canvas Toolbar */}
          <div className="absolute top-4 left-1/2 -translate-x-1/2 flex items-center gap-1 bg-[#1c1d27]/90 backdrop-blur border border-[#3b3f54] p-1 rounded-xl shadow-2xl z-40">
            <button className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]">
              <span className="material-symbols-outlined">near_me</span>
            </button>
            <div className="w-px h-6 bg-[#3b3f54] mx-1"></div>
            <button className="p-2 rounded-lg bg-blue-600 text-white">
              <span className="material-symbols-outlined">brush</span>
            </button>
            <div className="flex items-center gap-2 px-2">
              {slots.map(slot => (
                <button
                  key={slot.id}
                  onClick={() => setActiveColor(slot.color)}
                  className={`w-6 h-6 rounded-full border-2 transition-all ${activeColor === slot.color ? 'border-white ring-2 ring-white/20 scale-110' : 'border-transparent hover:border-white/50'}`}
                  style={{ backgroundColor: slot.color }}
                  title={slot.name}
                />
              ))}
            </div>
            <div className="w-px h-6 bg-[#3b3f54] mx-1"></div>
            <button onClick={() => {
              const ctx = canvasRef.current?.getContext('2d');
              ctx?.clearRect(0, 0, 1000, 562);
            }} className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]">
              <span className="material-symbols-outlined">ink_eraser</span>
            </button>
            <button className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]">
              <span className="material-symbols-outlined">zoom_in</span>
            </button>
          </div>

          <div className="flex-1 flex items-center justify-center p-8 canvas-bg relative">
            <div className="relative bg-[#1c1d27] rounded-lg border border-[#3b3f54] shadow-2xl aspect-video w-full max-w-5xl overflow-hidden group">
              {/* Generated Image Preview or Base Sketch */}
              {generatedImages.length > 0 ? (
                <img src={generatedImages[0]} className="w-full h-full object-cover" alt="Generated Output" />
              ) : (
                <img 
                  ref={bgImageRef}
                  alt="스토리보드 스케치" 
                  className="w-full h-full object-cover opacity-60" 
                  src="https://picsum.photos/1920/1080?random=99" 
                />
              )}

              {/* Masking Canvas */}
              <canvas
                ref={canvasRef}
                width={1000}
                height={562}
                onMouseDown={startDrawing}
                onMouseMove={draw}
                onMouseUp={endDrawing}
                onMouseLeave={endDrawing}
                className={`absolute inset-0 w-full h-full cursor-crosshair opacity-60 pointer-events-auto ${generatedImages.length > 0 ? 'hidden' : ''}`}
              />

              <div className="absolute bottom-4 right-4 flex gap-2">
                {slots.filter(s => s.image).map(slot => (
                  <button key={slot.id} className="bg-[#191919]/80 backdrop-blur px-3 py-1.5 rounded-lg border border-[#3b3f54] text-[10px] font-bold uppercase tracking-wider flex items-center gap-2 text-white">
                    <span className="w-2 h-2 rounded-full" style={{ backgroundColor: slot.color }}></span> {slot.type}
                  </button>
                ))}
              </div>

              {isGenerating && (
                <div className="absolute inset-0 bg-black/70 flex flex-col items-center justify-center z-50">
                  <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                  <p className="text-xl font-bold text-white mb-2">시안을 생성하는 중...</p>
                  <p className="text-sm text-blue-400">구도와 레퍼런스를 매핑하고 있습니다</p>
                </div>
              )}
            </div>
          </div>

          {/* Steps Footer */}
          <footer className="h-16 bg-[#1c1d27] border-t border-[#3b3f54] flex items-center justify-center px-6 shrink-0">
            <nav className="flex items-center w-full max-w-4xl justify-between">
              <div className="flex items-center gap-3 text-[#555a77]">
                <span className="text-sm font-bold">01</span>
                <span className="text-xs uppercase tracking-widest font-bold">설정</span>
                <span className="material-symbols-outlined text-sm">chevron_right</span>
              </div>
              <div className="flex items-center gap-3 text-blue-500 border-b-2 border-blue-500 h-16 px-4">
                <span className="text-sm font-bold">02</span>
                <span className="text-xs uppercase tracking-widest font-bold">배치</span>
              </div>
              <div className="flex items-center gap-3 text-[#555a77]">
                <span className="material-symbols-outlined text-sm">chevron_right</span>
                <span className="text-sm font-bold">03</span>
                <span className="text-xs uppercase tracking-widest font-bold">아트 디렉팅</span>
              </div>
              <div className="flex items-center gap-3 text-[#555a77]">
                <span className="material-symbols-outlined text-sm">chevron_right</span>
                <span className="text-sm font-bold">04</span>
                <span className="text-xs uppercase tracking-widest font-bold">생성</span>
              </div>
            </nav>
            <div className="absolute right-6 flex gap-2">
              {generatedImages.length > 0 && (
                <button 
                  onClick={() => setGeneratedImages([])}
                  className="bg-[#1c1d27] border border-[#3b3f54] text-[#9da1b9] text-xs font-bold px-4 py-2 rounded-lg flex items-center gap-2 hover:text-white"
                >
                  초기화
                </button>
              )}
              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className={`bg-blue-600 text-white text-xs font-bold px-6 py-2 rounded-lg flex items-center gap-2 transition-all ${isGenerating ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-700'}`}
              >
                {isGenerating ? '처리 중...' : '다음 단계'} <span className="material-symbols-outlined text-sm">arrow_forward</span>
              </button>
            </div>
          </footer>
        </main>

        {/* Right Sidebar */}
        <aside className="w-80 border-l border-[#3b3f54] bg-[#191919] flex flex-col overflow-y-auto">
          <div className="p-4 space-y-6">
            <section>
              <div className="flex items-center gap-2 mb-4">
                <span className="material-symbols-outlined text-blue-500 text-lg">grid_view</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">객체별 참조 관리</h3>
              </div>
              <div className="space-y-4">
                {slots.map(slot => (
                  <div key={slot.id} className="p-3 bg-[#1c1d27] border-l-4 rounded-lg space-y-3" style={{ borderLeftColor: slot.color }}>
                    <div className="flex justify-between items-center">
                      <span className="text-[10px] font-bold uppercase" style={{ color: slot.color }}>{slot.name}</span>
                      <span className="text-[10px] text-[#9da1b9]">{slot.type}</span>
                    </div>
                    <div 
                      onClick={() => handleSlotUpload(slot.id)}
                      className="aspect-square bg-[#191919] border border-dashed border-[#3b3f54] rounded flex flex-col items-center justify-center cursor-pointer hover:bg-[#3b3f54]/20 transition-all group overflow-hidden relative"
                    >
                      {slot.image ? (
                        <img className="w-full h-full object-cover" src={slot.image} alt={slot.type} />
                      ) : (
                        <>
                          <span className="material-symbols-outlined text-[#3b3f54] text-3xl mb-1">upload_file</span>
                          <p className="text-[10px] text-[#555a77] uppercase font-bold">참조 이미지 업로드</p>
                        </>
                      )}
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                        <span className="material-symbols-outlined text-white">add_a_photo</span>
                      </div>
                    </div>
                    {slot.image && (
                      <div className="flex justify-between text-[10px] text-[#555a77]">
                        <span>참조: uploaded_asset.jpg</span>
                        <span className="text-green-500">{slot.confidence}% 일치</span>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </section>

            <section className="pt-4 border-t border-[#3b3f54]">
              <div className="flex items-center gap-2 mb-4">
                <span className="material-symbols-outlined text-blue-500 text-lg">palette</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">스타일 참조</h3>
              </div>
              <div className="p-3 bg-[#1c1d27] border border-[#3b3f54] rounded-xl space-y-3">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 rounded bg-[#191919] border border-[#3b3f54] flex items-center justify-center overflow-hidden bg-cover bg-center" style={{ backgroundImage: `url('https://picsum.photos/200/200?random=15')` }}>
                  </div>
                  <div className="flex-1">
                    <p className="text-[10px] font-bold text-white uppercase tracking-tight">스타일: 네오 누아르 유화</p>
                    <div className="w-full bg-[#191919] h-1 rounded-full mt-1">
                      <div className="bg-blue-600 w-[70%] h-full rounded-full"></div>
                    </div>
                  </div>
                </div>
