import { generateDirectorImage } from './services/geminiService';

const DEFAULT_SLOTS: ReferenceSlot[] = [
  { id: 'A', color: 'rgb(239, 68, 68)', name: '슬롯 A (빨강)', type: '캐릭터 얼굴', image: 'https://picsum.photos/400/400?random=1', confidence: 88 },
  { id: 'B', color: 'rgb(59, 130, 246)', name: '슬롯 B (파랑)', type: '환경 소품' },
  { id: 'C', color: 'rgb(234, 179, 8)', name: '슬롯 C (노랑)', type: '추가 요소' },
];

const INITIAL_LAYERS: StoryboardLayer[] = [
  { id: 'l1', name: '컬러 마스크 레이어', type: 'mask', visible: true, locked: false, active: true },
  { id: 'l2', name: '기본 스토리보드', type: 'base', visible: true, locked: true },
];

const App: React.FC = () => {
  const [projectInfo] = useState<ProjectInfo>({
    date: new Date().toLocaleDateString('ko-KR'),
    resolution: '1920 x 1080',
    description: '',
  });
  const [description, setDescription] = useState('');
  const [layers, setLayers] = useState<StoryboardLayer[]>(INITIAL_LAYERS);
  const [slots, setSlots] = useState<ReferenceSlot[]>(DEFAULT_SLOTS);
  const [activeColor, setActiveColor] = useState(DEFAULT_SLOTS[0].color);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
  const [baseImage, setBaseImage] = useState<string>('https://picsum.photos/1920/1080?random=99');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const bgImageRef = useRef<HTMLImageElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Setup canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = 20;
  }, []);

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.strokeStyle = activeColor;
    setIsDrawing(true);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const endDrawing = () => {
    setIsDrawing(false);
  };

  const handleGenerate = async () => {
    if (isGenerating) return;
    setIsGenerating(true);

    try {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const maskData = canvas.toDataURL('image/png');
      const activeRefs = slots
        .filter(s => s.image)
        .map(s => ({ color: s.color, type: s.type, image: s.image! }));

      const results = await generateDirectorImage(baseImage, maskData, description, activeRefs);
      setGeneratedImages(results);
    } catch (err) {
      alert("이미지 생성에 실패했습니다. API 키나 네트워크 상태를 확인해주세요.");
