import { generateDirectorImage } from './services/geminiService';

const INITIAL_SLOTS: ReferenceSlot[] = [
  { id: 'A', color: 'rgb(239, 68, 68)', name: '슬롯 A (빨강)', type: '캐릭터 얼굴', image: 'https://picsum.photos/400/400?random=1', confidence: 88 },
  { id: 'B', color: 'rgb(59, 130, 246)', name: '슬롯 B (파랑)', type: '환경 소품' },
  { id: 'C', color: 'rgb(234, 179, 8)', name: '슬롯 C (노랑)', type: '추가 요소' },
];

const COLOR_PALETTE = [
  'rgb(168, 85, 247)', // Purple
  'rgb(34, 197, 94)',  // Green
  'rgb(249, 115, 22)', // Orange
  'rgb(236, 72, 153)', // Pink
  'rgb(20, 184, 166)', // Teal
  'rgb(99, 102, 241)', // Indigo
];

const INITIAL_LAYERS: StoryboardLayer[] = [
  { id: 'l1', name: '컬러 마스크 레이어', type: 'mask', visible: true, locked: false, active: true },
  { id: 'l2', name: '기본 스토리보드', type: 'base', visible: true, locked: true },
];

const App: React.FC = () => {
  const [projectInfo] = useState<ProjectInfo>({
    date: new Date().toLocaleDateString('ko-KR'),
    resolution: '1920 x 1080',
    description: '',
  });
  const [description, setDescription] = useState('');
  const [layers] = useState<StoryboardLayer[]>(INITIAL_LAYERS);
  const [slots, setSlots] = useState<ReferenceSlot[]>(INITIAL_SLOTS);
  const [activeColor, setActiveColor] = useState(INITIAL_SLOTS[0].color);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
  const [baseImage, setBaseImage] = useState<string>('https://picsum.photos/1920/1080?random=99');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const bgImageRef = useRef<HTMLImageElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Setup canvas defaults
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = 20;
  }, []);

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.strokeStyle = activeColor;
    setIsDrawing(true);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const endDrawing = () => {
    setIsDrawing(false);
  };

  const handleGenerate = async () => {
    if (isGenerating) return;
    setIsGenerating(true);

    try {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const maskData = canvas.toDataURL('image/png');
      const activeRefs = slots
        .filter(s => s.image)
        .map(s => ({ color: s.color, type: s.type, image: s.image! }));

      const results = await generateDirectorImage(baseImage, maskData, description, activeRefs);
      setGeneratedImages(results);
    } catch (err) {
      alert("이미지 생성에 실패했습니다. API 키나 네트워크 상태를 확인해주세요.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSlotUpload = (id: string) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setSlots(prev => prev.map(s => s.id === id ? { ...s, image: base64 } : s));
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const handleBaseUpload = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setBaseImage(base64);
          setGeneratedImages([]); 
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const handleResetAll = () => {
    if (window.confirm("프로젝트를 초기화하시겠습니까? 모든 입력 내용이 삭제됩니다.")) {
      setDescription('');
      setGeneratedImages([]);
      setSlots(INITIAL_SLOTS);
      setActiveColor(INITIAL_SLOTS[0].color);
      setBaseImage('https://picsum.photos/1920/1080?random=' + Math.floor(Math.random() * 1000));
      const ctx = canvasRef.current?.getContext('2d');
      ctx?.clearRect(0, 0, 1000, 562);
    }
  };

  const handleAddSlot = () => {
    const nextIndex = slots.length;
    const color = COLOR_PALETTE[nextIndex % COLOR_PALETTE.length];
    const newSlot: ReferenceSlot = {
      id: `S${nextIndex + 1}`,
      color: color,
      name: `슬롯 ${String.fromCharCode(65 + nextIndex)}`,
      type: '새 객체 타입'
    };
    setSlots([...slots, newSlot]);
    setActiveColor(color);
  };

  const removeSlot = (id: string) => {
    if (slots.length <= 1) return;
    setSlots(slots.filter(s => s.id !== id));
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#191919]">
      {/* Header */}
      <header className="flex items-center justify-between px-6 py-3 border-b border-[#3b3f54] bg-[#1c1d27]/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-4">
          <div className="w-8 h-8 text-[#f7f7f7]">
            <svg fill="none" viewBox="0 0 48 48" xmlns="http://www.w3.org/2000/svg">
              <path d="M36.7273 44C33.9891 44 31.6043 39.8386 30.3636 33.69C29.123 39.8386 26.7382 44 24 44C21.2618 44 18.877 39.8386 17.6364 33.69C16.3957 39.8386 14.0109 44 11.2727 44C7.25611 44 4 35.0457 4 24C4 12.9543 7.25611 4 11.2727 4C14.0109 4 16.3957 8.16144 17.6364 14.31C18.877 8.16144 21.2618 4 24 4C26.7382 4 29.123 8.16144 30.3636 14.31C31.6043 8.16144 33.9891 4 36.7273 4C40.7439 4 44 12.9543 44 24C44 35.0457 40.7439 44 36.7273 44Z" fill="#2563eb" />
            </svg>
          </div>
          <div className="flex flex-col">
            <h2 className="text-white text-base font-bold leading-tight tracking-tight">Director-Centric AI</h2>
            <p className="text-[#9da1b9] text-xs font-normal">스토리보드 리마스터링 스튜디오</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2 bg-[#1c1d27]/50 px-3 py-1 rounded-full border border-[#3b3f54]">
            <span className="material-symbols-outlined text-sm text-green-400">verified_user</span>
            <span className="text-[10px] uppercase tracking-widest font-bold text-white">Director Engine 2.5 Active</span>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={handleResetAll}
              className="flex items-center justify-center rounded-lg h-9 px-4 bg-[#1c1d27] text-white text-sm font-bold border border-[#3b3f54] transition-all hover:bg-[#3b3f54] gap-2"
            >
              <span className="material-symbols-outlined text-sm">refresh</span>
              새 프로젝트
            </button>
            <button className="flex items-center justify-center rounded-lg h-9 px-4 bg-[#2563eb] text-white text-sm font-bold transition-all hover:opacity-90">
              저장하기
            </button>
          </div>
          <div className="w-9 h-9 rounded-full border-2 border-blue-500/40 bg-cover" style={{ backgroundImage: `url('https://picsum.photos/100/100?u=1')` }} />
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">
        {/* Left Sidebar */}
        <aside className="w-80 border-r border-[#3b3f54] bg-[#191919] flex flex-col overflow-y-auto">
          <div className="p-4 space-y-6">
            <section>
              <div className="flex items-center gap-2 mb-3">
                <span className="material-symbols-outlined text-blue-500 text-lg">info</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">프로젝트 정보</h3>
              </div>
              <div className="bg-[#1c1d27] border border-[#3b3f54] rounded-lg p-3 space-y-2">
                <div className="flex justify-between items-center text-xs">
                  <span className="text-[#9da1b9]">생성 일자</span>
                  <span className="text-white">{projectInfo.date}</span>
                </div>
                <div className="flex justify-between items-center text-xs">
                  <span className="text-[#9da1b9]">출력 해상도</span>
                  <span className="text-white">{projectInfo.resolution}</span>
                </div>
              </div>
            </section>

            <section>
              <div className="flex items-center gap-2 mb-3">
                <span className="material-symbols-outlined text-blue-500 text-lg">auto_awesome</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">디렉팅 프롬프트</h3>
              </div>
              <div className="relative group">
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="w-full bg-[#1c1d27] border border-[#3b3f54] rounded-lg p-3 text-sm text-white placeholder:text-[#555a77] focus:ring-1 focus:ring-blue-500 focus:border-blue-500 min-h-[120px] resize-none outline-none"
                  placeholder="캐릭터의 감정, 빛의 방향, 대기질 등을 구체적으로 설명해주세요..."
                />
              </div>
            </section>

            <section>
              <div className="flex items-center justify-between mb-3 px-1">
                <div className="flex items-center gap-2">
                  <span className="material-symbols-outlined text-blue-500 text-lg">layers</span>
                  <h3 className="text-white text-sm font-bold uppercase tracking-wider">레이어 관리</h3>
                </div>
                <button className="text-[#9da1b9] hover:text-white" onClick={handleBaseUpload} title="새 콘티 업로드">
                  <span className="material-symbols-outlined text-lg">upload_file</span>
                </button>
              </div>
              <div className="space-y-1">
                {layers.map(layer => (
                  <div key={layer.id} className={`flex items-center gap-3 p-2 rounded-lg group ${layer.active ? 'bg-blue-500/10 border border-blue-500/30' : 'bg-[#1c1d27]/30 border border-transparent hover:border-[#3b3f54]'}`}>
                    <span className="material-symbols-outlined text-[#555a77] text-sm cursor-grab">drag_indicator</span>
                    <div className="w-10 h-10 rounded border border-[#3b3f54] flex items-center justify-center overflow-hidden bg-[#1c1d27]">
                      {layer.type === 'mask' ? (
                        <div className="bg-gradient-to-br from-red-500 to-purple-500 w-4 h-4 rounded-full" />
                      ) : (
                        <div className="w-full h-full bg-cover bg-center" style={{ backgroundImage: `url('${baseImage}')` }} />
                      )}
                    </div>
                    <div className="flex-1 overflow-hidden">
                      <p className={`text-xs font-bold truncate ${layer.active ? 'text-white' : 'text-[#9da1b9]'}`}>{layer.name}</p>
                      <p className="text-[10px] text-[#555a77]">{layer.type === 'mask' ? `${slots.length}개 마스킹 영역` : '콘티 (배경)'}</p>
                    </div>
                    {layer.type === 'base' && (
                      <button onClick={handleBaseUpload} className="opacity-0 group-hover:opacity-100 transition-opacity bg-blue-600/20 hover:bg-blue-600/40 p-1 rounded">
                        <span className="material-symbols-outlined text-sm text-blue-400">edit</span>
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </section>
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 bg-[#191919] flex flex-col relative">
          <div className="absolute top-2 left-6 z-40">
            <h1 className="text-[#555a77] text-[10px] font-bold uppercase tracking-widest mt-4">Storyboard Director View</h1>
          </div>

          {/* Canvas Toolbar */}
          <div className="absolute top-4 left-1/2 -translate-x-1/2 flex items-center gap-1 bg-[#1c1d27]/90 backdrop-blur border border-[#3b3f54] p-1 rounded-xl shadow-2xl z-40">
            <button className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]">
              <span className="material-symbols-outlined">near_me</span>
            </button>
            <div className="w-px h-6 bg-[#3b3f54] mx-1"></div>
            <button className="p-2 rounded-lg bg-blue-600 text-white">
              <span className="material-symbols-outlined">brush</span>
            </button>
            <div className="flex items-center gap-2 px-2 overflow-x-auto max-w-[400px] no-scrollbar">
              {slots.map(slot => (
                <button
                  key={slot.id}
                  onClick={() => setActiveColor(slot.color)}
                  className={`w-6 h-6 rounded-full border-2 shrink-0 transition-all ${activeColor === slot.color ? 'border-white ring-2 ring-white/20 scale-110' : 'border-transparent hover:border-white/50'}`}
                  style={{ backgroundColor: slot.color }}
                  title={slot.name}
                />
              ))}
              <button 
                onClick={handleAddSlot}
                className="w-6 h-6 rounded-full border border-dashed border-[#555a77] flex items-center justify-center hover:border-white transition-colors shrink-0"
                title="마스킹 컬러 추가"
              >
                <span className="material-symbols-outlined text-xs text-[#555a77] hover:text-white">add</span>
              </button>
            </div>
            <div className="w-px h-6 bg-[#3b3f54] mx-1"></div>
            <button onClick={() => {
              const ctx = canvasRef.current?.getContext('2d');
              ctx?.clearRect(0, 0, 1000, 562);
            }} className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]" title="마스크 초기화">
              <span className="material-symbols-outlined">ink_eraser</span>
            </button>
            <button className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]" onClick={handleBaseUpload} title="콘티 업로드">
              <span className="material-symbols-outlined">add_photo_alternate</span>
            </button>
          </div>

          <div className="flex-1 flex items-center justify-center p-8 canvas-bg relative">
            <div className="relative bg-[#1c1d27] rounded-lg border border-[#3b3f54] shadow-2xl aspect-video w-full max-w-5xl overflow-hidden group">
              {/* Base Sketch */}
              <img 
                ref={bgImageRef}
                alt="콘티 스케치" 
                className={`w-full h-full object-cover transition-opacity duration-500 ${generatedImages.length > 0 ? 'opacity-30' : 'opacity-60'}`} 
                src={baseImage} 
              />

              {/* Masking Canvas */}
              <canvas
                ref={canvasRef}
                width={1000}
                height={562}
                onMouseDown={startDrawing}
                onMouseMove={draw}
                onMouseUp={endDrawing}
                onMouseLeave={endDrawing}
                className={`absolute inset-0 w-full h-full cursor-crosshair opacity-70 pointer-events-auto ${generatedImages.length > 0 ? 'hidden' : ''}`}
              />

              {/* Generated Image Preview */}
              {generatedImages.length > 0 && (
                <div className="absolute inset-0 z-10 animate-in fade-in duration-700">
                   <img src={generatedImages[0]} className="w-full h-full object-cover" alt="Generated Output" />
                </div>
              )}

              <div className="absolute bottom-4 left-4 z-20 flex flex-wrap gap-2 max-w-[80%]">
                {slots.filter(s => s.image).map(slot => (
                  <button key={slot.id} className="bg-[#191919]/80 backdrop-blur px-3 py-1.5 rounded-lg border border-[#3b3f54] text-[10px] font-bold uppercase tracking-wider flex items-center gap-2 text-white shadow-lg">
                    <span className="w-2 h-2 rounded-full" style={{ backgroundColor: slot.color }}></span> {slot.type}
                  </button>
                ))}
              </div>

              {isGenerating && (
                <div className="absolute inset-0 bg-black/70 flex flex-col items-center justify-center z-50">
                  <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                  <p className="text-xl font-bold text-white mb-2">Director AI가 연출 중입니다...</p>
                  <p className="text-sm text-blue-400">마스크 영역과 레퍼런스를 정교하게 매칭하고 있습니다</p>
                </div>
              )}
            </div>
          </div>

          {/* Steps Footer */}
          <footer className="h-16 bg-[#1c1d27] border-t border-[#3b3f54] flex items-center justify-center px-6 shrink-0">
            <nav className="flex items-center w-full max-w-4xl justify-between">
              <div className="flex items-center gap-3 text-[#555a77]">
                <span className="text-sm font-bold">01</span>
                <span className="text-xs uppercase tracking-widest font-bold">콘티 준비</span>
                <span className="material-symbols-outlined text-sm">chevron_right</span>
              </div>
              <div className="flex items-center gap-3 text-blue-500 border-b-2 border-blue-500 h-16 px-4">
                <span className="text-sm font-bold">02</span>
                <span className="text-xs uppercase tracking-widest font-bold">마스킹 & 참조</span>
              </div>
              <div className="flex items-center gap-3 text-[#555a77]">
                <span className="material-symbols-outlined text-sm">chevron_right</span>
                <span className="text-sm font-bold">03</span>
                <span className="text-xs uppercase tracking-widest font-bold">디테일 생성</span>
              </div>
            </nav>
            <div className="absolute right-6 flex gap-2">
              {generatedImages.length > 0 && (
                <button 
                  onClick={() => setGeneratedImages([])}
                  className="bg-[#1c1d27] border border-[#3b3f54] text-[#9da1b9] text-xs font-bold px-4 py-2 rounded-lg flex items-center gap-2 hover:text-white transition-all"
                >
                  <span className="material-symbols-outlined text-sm">undo</span>
                  수정하기
                </button>
              )}
              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className={`bg-blue-600 text-white text-xs font-bold px-6 py-2 rounded-lg flex items-center gap-2 transition-all ${isGenerating ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-700 shadow-lg shadow-blue-600/20'}`}
              >
                {isGenerating ? '처리 중...' : generatedImages.length > 0 ? '다시 생성' : '이미지 생성'} <span className="material-symbols-outlined text-sm">auto_fix_high</span>
              </button>
            </div>
          </footer>
        </main>

        {/* Right Sidebar */}
        <aside className="w-80 border-l border-[#3b3f54] bg-[#191919] flex flex-col overflow-y-auto">
          <div className="p-4 space-y-6">
            <section>
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <span className="material-symbols-outlined text-blue-500 text-lg">grid_view</span>
                  <h3 className="text-white text-sm font-bold uppercase tracking-wider">참조 이미지 매핑</h3>
                </div>
                <button 
                  onClick={handleAddSlot}
                  className="w-7 h-7 bg-blue-600/20 hover:bg-blue-600 transition-colors rounded-full flex items-center justify-center text-blue-400 hover:text-white"
                  title="새 슬롯 추가"
                >
                  <span className="material-symbols-outlined text-sm">add</span>
                </button>
              </div>
              <div className="space-y-4">
                {slots.map((slot, index) => (
                  <div key={slot.id} className="p-3 bg-[#1c1d27] border-l-4 rounded-lg space-y-3 shadow-md group/slot" style={{ borderLeftColor: slot.color }}>
                    <div className="flex justify-between items-center">
                      <input 
                        className="bg-transparent text-[10px] font-bold uppercase focus:outline-none w-2/3"
                        style={{ color: slot.color }}
                        value={slot.name}
                        onChange={(e) => {
                          const newName = e.target.value;
                          setSlots(slots.map(s => s.id === slot.id ? {...s, name: newName} : s));
                        }}
                      />
                      <div className="flex gap-1 items-center">
                        <button onClick={() => removeSlot(slot.id)} className="opacity-0 group-hover/slot:opacity-100 transition-opacity text-[#555a77] hover:text-red-500">
                          <span className="material-symbols-outlined text-xs">delete</span>
                        </button>
                        <span className="text-[10px] text-[#9da1b9] bg-[#191919] px-1 rounded">{slot.id}</span>
                      </div>
                    </div>
                    <input 
                      className="w-full bg-[#191919] text-[10px] text-[#9da1b9] border border-[#3b3f54] rounded px-2 py-1 focus:border-blue-500 outline-none"
                      value={slot.type}
                      placeholder="객체 타입 (예: 캐릭터, 산, 바다...)"
                      onChange={(e) => {
                        const newType = e.target.value;
                        setSlots(slots.map(s => s.id === slot.id ? {...s, type: newType} : s));
                      }}
                    />
                    <div 
                      onClick={() => handleSlotUpload(slot.id)}
                      className="aspect-square bg-[#191919] border border-dashed border-[#3b3f54] rounded flex flex-col items-center justify-center cursor-pointer hover:bg-[#3b3f54]/20 transition-all group overflow-hidden relative"
                    >
                      {slot.image ? (
                        <img className="w-full h-full object-cover" src={slot.image} alt={slot.type} />
                      ) : (
                        <>
                          <span className="material-symbols-outlined text-[#3b3f54] text-3xl mb-1">upload_file</span>
                          <p className="text-[10px] text-[#555a77] uppercase font-bold text-center px-4 leading-tight">클릭하여 참조 이미지 추가</p>
                        </>
                      )}
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                        <span className="material-symbols-outlined text-white">add_a_photo</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </section>

            <section className="pt-4 border-t border-[#3b3f54]">
              <div className="flex items-center gap-2 mb-4">
                <span className="material-symbols-outlined text-blue-500 text-lg">palette</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">스타일 가이드</h3>
              </div>
              <div className="p-3 bg-[#1c1d27] border border-[#3b3f54] rounded-xl space-y-3">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 rounded bg-[#191919] border border-[#3b3f54] flex items-center justify-center overflow-hidden bg-cover bg-center" style={{ backgroundImage: `url('https://picsum.photos/200/200?random=15')` }}>
                  </div>
                  <div className="flex-1">
                    <p className="text-[10px] font-bold text-white uppercase tracking-tight">네오 누아르 시네마틱</p>
                    <p className="text-[9px] text-[#9da1b9] uppercase">Deep Shadows / Oil Texture</p>
                  </div>
                </div>
                <button className="w-full py-2 border border-[#3b3f54] rounded text-[10px] font-bold uppercase text-[#9da1b9] hover:bg-[#3b3f54] hover:text-white transition-all">
                  커스텀 스타일 학습
                </button>
              </div>
            </section>
          </div>
        </aside>
      </div>
    </div>
  );
};

export default App;

export interface ReferenceSlot {
  id: string;
  color: string;
  name: string;
  type: string;
  image?: string;
  confidence?: number;
}

export interface StoryboardLayer {
  id: string;
  name: string;
  type: 'mask' | 'base';
  visible: boolean;
  locked: boolean;
  active?: boolean;
}

export interface ProjectInfo {
  date: string;
  resolution: string;
  description: string;
}

export interface StylePreset {
  id: string;
  name: string;
  description: string;
  preview: string;
  promptHint: string;
}

import React, { useState, useRef, useEffect } from 'react';
import { StoryboardLayer, ReferenceSlot, ProjectInfo, StylePreset } from './types';
import { generateDirectorImage } from './services/geminiService';

const INITIAL_SLOTS: ReferenceSlot[] = [
  { id: 'A', color: '#ef4444', name: '슬롯 A (빨강)', type: '캐릭터 얼굴', image: 'https://picsum.photos/400/400?random=1', confidence: 88 },
  { id: 'B', color: '#3b82f6', name: '슬롯 B (파랑)', type: '환경 소품' },
  { id: 'C', color: '#eab308', name: '슬롯 C (노랑)', type: '추가 요소' },
];

const STYLE_PRESETS: StylePreset[] = [
  { id: 'neo-noir', name: '네오 누아르', description: '강한 대비, 차가운 톤', preview: 'https://picsum.photos/200/200?random=15', promptHint: 'Neo-Noir Oil Painting style. Rich textures, dramatic lighting, and deep shadows.' },
  { id: 'ghibli', name: '지브리 스타일', description: '부드러운 색감, 자연광', preview: 'https://picsum.photos/200/200?random=16', promptHint: 'Studio Ghibli anime style. Soft hand-painted textures, vibrant natural lighting, whimsical atmosphere.' },
  { id: 'cyberpunk', name: '사이버펑크', description: '네온 조명, 하이테크', preview: 'https://picsum.photos/200/200?random=17', promptHint: 'Cyberpunk cinematic style. Neon lights, rainy atmosphere, high-tech details, futuristic grit.' },
  { id: 'watercolor', name: '수채화', description: '맑고 번지는 느낌', preview: 'https://picsum.photos/200/200?random=18', promptHint: 'Fluid watercolor painting. Bleeding edges, paper texture, soft pastels, artistic and organic.' },
];

const COLOR_PALETTE = [
  '#a855f7', // Purple
  '#22c55e', // Green
  '#f97316', // Orange
  '#ec4899', // Pink
  '#14b8a6', // Teal
  '#6366f1', // Indigo
];

const INITIAL_LAYERS: StoryboardLayer[] = [
  { id: 'l1', name: '컬러 마스크 레이어', type: 'mask', visible: true, locked: false, active: true },
  { id: 'l2', name: '기본 스토리보드', type: 'base', visible: true, locked: true },
];

const App: React.FC = () => {
  const [projectInfo] = useState<ProjectInfo>({
    date: new Date().toLocaleDateString('ko-KR'),
    resolution: '1920 x 1080',
    description: '',
  });
  const [description, setDescription] = useState('');
  const [layers] = useState<StoryboardLayer[]>(INITIAL_LAYERS);
  const [slots, setSlots] = useState<ReferenceSlot[]>(INITIAL_SLOTS);
  const [activeColor, setActiveColor] = useState(INITIAL_SLOTS[0].color);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
  const [baseImage, setBaseImage] = useState<string>('https://picsum.photos/1920/1080?random=99');

  const [selectedStyleId, setSelectedStyleId] = useState<string>(STYLE_PRESETS[0].id);
  const [customStyleImage, setCustomStyleImage] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const bgImageRef = useRef<HTMLImageElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Setup canvas defaults
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = 20;
  }, []);

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.strokeStyle = activeColor;
    setIsDrawing(true);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const endDrawing = () => {
    setIsDrawing(false);
  };

  const handleGenerate = async () => {
    if (isGenerating) return;
    setIsGenerating(true);

    try {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const maskData = canvas.toDataURL('image/png');
      const activeRefs = slots
        .filter(s => s.image)
        .map(s => ({ color: s.color, type: s.type, image: s.image! }));

      const currentStyle = STYLE_PRESETS.find(s => s.id === selectedStyleId);
      const stylePrompt = selectedStyleId === 'custom' && customStyleImage 
        ? "Follow the style of the custom style reference image provided." 
        : (currentStyle?.promptHint || "");

      const finalDescription = `${description}\n\nStyle Guide: ${stylePrompt}`;

      const results = await generateDirectorImage(baseImage, maskData, finalDescription, activeRefs);
      setGeneratedImages(results);
    } catch (err) {
      alert("이미지 생성에 실패했습니다. API 키나 네트워크 상태를 확인해주세요.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSlotUpload = (id: string) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setSlots(prev => prev.map(s => s.id === id ? { ...s, image: base64 } : s));
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const handleCustomStyleUpload = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setCustomStyleImage(base64);
          setSelectedStyleId('custom');
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const handleBaseUpload = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setBaseImage(base64);
          setGeneratedImages([]); 
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const handleResetAll = () => {
    if (window.confirm("프로젝트를 초기화하시겠습니까? 모든 입력 내용이 삭제됩니다.")) {
      setDescription('');
      setGeneratedImages([]);
      setSlots(INITIAL_SLOTS);
      setActiveColor(INITIAL_SLOTS[0].color);
      setBaseImage('https://picsum.photos/1920/1080?random=' + Math.floor(Math.random() * 1000));
      setCustomStyleImage(null);
      setSelectedStyleId(STYLE_PRESETS[0].id);
      const ctx = canvasRef.current?.getContext('2d');
      ctx?.clearRect(0, 0, 1000, 562);
    }
  };

  const handleAddSlot = () => {
    const nextIndex = slots.length;
    const color = COLOR_PALETTE[nextIndex % COLOR_PALETTE.length];
    const newSlot: ReferenceSlot = {
      id: `S${nextIndex + 1}`,
      color: color,
      name: `슬롯 ${String.fromCharCode(65 + nextIndex)}`,
      type: '새 객체 타입'
    };
    setSlots([...slots, newSlot]);
    setActiveColor(color);
  };

  const removeSlot = (id: string) => {
    if (slots.length <= 1) return;
    setSlots(slots.filter(s => s.id !== id));
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#191919]">
      {/* Header */}
      <header className="flex items-center justify-between px-6 py-3 border-b border-[#3b3f54] bg-[#1c1d27]/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-4">
          <div className="w-8 h-8 text-[#f7f7f7]">
            <svg fill="none" viewBox="0 0 48 48" xmlns="http://www.w3.org/2000/svg">
              <path d="M36.7273 44C33.9891 44 31.6043 39.8386 30.3636 33.69C29.123 39.8386 26.7382 44 24 44C21.2618 44 18.877 39.8386 17.6364 33.69C16.3957 39.8386 14.0109 44 11.2727 44C7.25611 44 4 35.0457 4 24C4 12.9543 7.25611 4 11.2727 4C14.0109 4 16.3957 8.16144 17.6364 14.31C18.877 8.16144 21.2618 4 24 4C26.7382 4 29.123 8.16144 30.3636 14.31C31.6043 8.16144 33.9891 4 36.7273 4C40.7439 4 44 12.9543 44 24C44 35.0457 40.7439 44 36.7273 44Z" fill="#2563eb" />
            </svg>
          </div>
          <div className="flex flex-col">
            <h2 className="text-white text-base font-bold leading-tight tracking-tight">Director-Centric AI</h2>
            <p className="text-[#9da1b9] text-xs font-normal">스토리보드 리마스터링 스튜디오</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2 bg-[#1c1d27]/50 px-3 py-1 rounded-full border border-[#3b3f54]">
            <span className="material-symbols-outlined text-sm text-green-400">verified_user</span>
            <span className="text-[10px] uppercase tracking-widest font-bold text-white">Director Engine 2.5 Active</span>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={handleResetAll}
              className="flex items-center justify-center rounded-lg h-9 px-4 bg-[#1c1d27] text-white text-sm font-bold border border-[#3b3f54] transition-all hover:bg-[#3b3f54] gap-2"
            >
              <span className="material-symbols-outlined text-sm">refresh</span>
              새 프로젝트
            </button>
            <button className="flex items-center justify-center rounded-lg h-9 px-4 bg-[#2563eb] text-white text-sm font-bold transition-all hover:opacity-90">
              저장하기
            </button>
          </div>
          <div className="w-9 h-9 rounded-full border-2 border-blue-500/40 bg-cover" style={{ backgroundImage: `url('https://picsum.photos/100/100?u=1')` }} />
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">
        {/* Left Sidebar */}
        <aside className="w-80 border-r border-[#3b3f54] bg-[#191919] flex flex-col overflow-y-auto">
          <div className="p-4 space-y-6">
            <section>
              <div className="flex items-center gap-2 mb-3">
                <span className="material-symbols-outlined text-blue-500 text-lg">info</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">프로젝트 정보</h3>
              </div>
              <div className="bg-[#1c1d27] border border-[#3b3f54] rounded-lg p-3 space-y-2">
                <div className="flex justify-between items-center text-xs">
                  <span className="text-[#9da1b9]">생성 일자</span>
                  <span className="text-white">{projectInfo.date}</span>
                </div>
                <div className="flex justify-between items-center text-xs">
                  <span className="text-[#9da1b9]">출력 해상도</span>
                  <span className="text-white">{projectInfo.resolution}</span>
                </div>
              </div>
            </section>

            <section>
              <div className="flex items-center gap-2 mb-3">
                <span className="material-symbols-outlined text-blue-500 text-lg">auto_awesome</span>
                <h3 className="text-white text-sm font-bold uppercase tracking-wider">디렉팅 프롬프트</h3>
              </div>
              <div className="relative group">
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="w-full bg-[#1c1d27] border border-[#3b3f54] rounded-lg p-3 text-sm text-white placeholder:text-[#555a77] focus:ring-1 focus:ring-blue-500 focus:border-blue-500 min-h-[120px] resize-none outline-none"
                  placeholder="캐릭터의 감정, 빛의 방향, 대기질 등을 구체적으로 설명해주세요..."
                />
              </div>
            </section>

            <section>
              <div className="flex items-center justify-between mb-3 px-1">
                <div className="flex items-center gap-2">
                  <span className="material-symbols-outlined text-blue-500 text-lg">layers</span>
                  <h3 className="text-white text-sm font-bold uppercase tracking-wider">레이어 관리</h3>
                </div>
                <button className="text-[#9da1b9] hover:text-white" onClick={handleBaseUpload} title="새 콘티 업로드">
                  <span className="material-symbols-outlined text-lg">upload_file</span>
                </button>
              </div>
              <div className="space-y-1">
                {layers.map(layer => (
                  <div key={layer.id} className={`flex items-center gap-3 p-2 rounded-lg group ${layer.active ? 'bg-blue-500/10 border border-blue-500/30' : 'bg-[#1c1d27]/30 border border-transparent hover:border-[#3b3f54]'}`}>
                    <span className="material-symbols-outlined text-[#555a77] text-sm cursor-grab">drag_indicator</span>
                    <div className="w-10 h-10 rounded border border-[#3b3f54] flex items-center justify-center overflow-hidden bg-[#1c1d27]">
                      {layer.type === 'mask' ? (
                        <div className="bg-gradient-to-br from-red-500 to-purple-500 w-4 h-4 rounded-full" />
                      ) : (
                        <div className="w-full h-full bg-cover bg-center" style={{ backgroundImage: `url('${baseImage}')` }} />
                      )}
                    </div>
                    <div className="flex-1 overflow-hidden">
                      <p className={`text-xs font-bold truncate ${layer.active ? 'text-white' : 'text-[#9da1b9]'}`}>{layer.name}</p>
                      <p className="text-[10px] text-[#555a77]">{layer.type === 'mask' ? `${slots.length}개 마스킹 영역` : '콘티 (배경)'}</p>
                    </div>
                    {layer.type === 'base' && (
                      <button onClick={handleBaseUpload} className="opacity-0 group-hover:opacity-100 transition-opacity bg-blue-600/20 hover:bg-blue-600/40 p-1 rounded">
                        <span className="material-symbols-outlined text-sm text-blue-400">edit</span>
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </section>
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 bg-[#191919] flex flex-col relative">
          <div className="absolute top-2 left-6 z-40">
            <h1 className="text-[#555a77] text-[10px] font-bold uppercase tracking-widest mt-4">Storyboard Director View</h1>
          </div>

          {/* Canvas Toolbar */}
          <div className="absolute top-4 left-1/2 -translate-x-1/2 flex items-center gap-1 bg-[#1c1d27]/90 backdrop-blur border border-[#3b3f54] p-1 rounded-xl shadow-2xl z-40">
            <button className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]">
              <span className="material-symbols-outlined">near_me</span>
            </button>
            <div className="w-px h-6 bg-[#3b3f54] mx-1"></div>
            <button className="p-2 rounded-lg bg-blue-600 text-white">
              <span className="material-symbols-outlined">brush</span>
            </button>
            <div className="flex items-center gap-2 px-2 overflow-x-auto max-w-[400px] no-scrollbar">
              {slots.map(slot => (
                <button
                  key={slot.id}
                  onClick={() => setActiveColor(slot.color)}
                  className={`w-6 h-6 rounded-full border-2 shrink-0 transition-all ${activeColor === slot.color ? 'border-white ring-2 ring-white/20 scale-110' : 'border-transparent hover:border-white/50'}`}
                  style={{ backgroundColor: slot.color }}
                  title={slot.name}
                />
              ))}
              <button 
                onClick={handleAddSlot}
                className="w-6 h-6 rounded-full border border-dashed border-[#555a77] flex items-center justify-center hover:border-white transition-colors shrink-0"
                title="마스킹 컬러 추가"
              >
                <span className="material-symbols-outlined text-xs text-[#555a77] hover:text-white">add</span>
              </button>
            </div>
            <div className="w-px h-6 bg-[#3b3f54] mx-1"></div>
            <button onClick={() => {
              const ctx = canvasRef.current?.getContext('2d');
              ctx?.clearRect(0, 0, 1000, 562);
            }} className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]" title="마스크 초기화">
              <span className="material-symbols-outlined">ink_eraser</span>
            </button>
            <button className="p-2 rounded-lg hover:bg-[#3b3f54] text-[#9da1b9]" onClick={handleBaseUpload} title="콘티 업로드">
              <span className="material-symbols-outlined">add_photo_alternate</span>
            </button>
          </div>

          <div className="flex-1 flex items-center justify-center p-8 canvas-bg relative">
            <div className="relative bg-[#1c1d27] rounded-lg border border-[#3b3f54] shadow-2xl aspect-video w-full max-w-5xl overflow-hidden group">
              {/* Base Sketch */}
              <img 
                ref={bgImageRef}
                alt="콘티 스케치" 
                className={`w-full h-full object-cover transition-opacity duration-500 ${generatedImages.length > 0 ? 'opacity-30' : 'opacity-60'}`} 
                src={baseImage} 
              />

              {/* Masking Canvas */}
              <canvas
                ref={canvasRef}
                width={1000}
                height={562}
                onMouseDown={startDrawing}
                onMouseMove={draw}
                onMouseUp={endDrawing}
                onMouseLeave={endDrawing}
                className={`absolute inset-0 w-full h-full cursor-crosshair opacity-70 pointer-events-auto ${generatedImages.length > 0 ? 'hidden' : ''}`}
              />

              {/* Generated Image Preview */}
              {generatedImages.length > 0 && (
                <div className="absolute inset-0 z-10 animate-in fade-in duration-700">
                   <img src={generatedImages[0]} className="w-full h-full object-cover" alt="Generated Output" />
                </div>
              )}

              <div className="absolute bottom-4 left-4 z-20 flex flex-wrap gap-2 max-w-[80%]">
                {slots.filter(s => s.image).map(slot => (
                  <button key={slot.id} className="bg-[#191919]/80 backdrop-blur px-3 py-1.5 rounded-lg border border-[#3b3f54] text-[10px] font-bold uppercase tracking-wider flex items-center gap-2 text-white shadow-lg">
                    <span className="w-2 h-2 rounded-full" style={{ backgroundColor: slot.color }}></span> {slot.type}
                  </button>
                ))}
              </div>

              {isGenerating && (
                <div className="absolute inset-0 bg-black/70 flex flex-col items-center justify-center z-50">
                  <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                  <p className="text-xl font-bold text-white mb-2">Director AI가 연출 중입니다...</p>
                  <p className="text-sm text-blue-400">마스크 영역과 레퍼런스를 정교하게 매칭하고 있습니다</p>
                </div>
              )}
            </div>
          </div>

          {/* Steps Footer */}
          <footer className="h-16 bg-[#1c1d27] border-t border-[#3b3f54] flex items-center justify-center px-6 shrink-0">
            <nav className="flex items-center w-full max-w-4xl justify-between">
              <div className="flex items-center gap-3 text-[#555a77]">
                <span className="text-sm font-bold">01</span>
                <span className="text-xs uppercase tracking-widest font-bold">콘티 준비</span>
                <span className="material-symbols-outlined text-sm">chevron_right</span>
              </div>
              <div className="flex items-center gap-3 text-blue-500 border-b-2 border-blue-500 h-16 px-4">
                <span className="text-sm font-bold">02</span>
                <span className="text-xs uppercase tracking-widest font-bold">마스킹 & 참조</span>
              </div>
              <div className="flex items-center gap-3 text-[#555a77]">
                <span className="material-symbols-outlined text-sm">chevron_right</span>
                <span className="text-sm font-bold">03</span>
                <span className="text-xs uppercase tracking-widest font-bold">디테일 생성</span>
              </div>
            </nav>
            <div className="absolute right-6 flex gap-2">
              {generatedImages.length > 0 && (
                <button 
                  onClick={() => setGeneratedImages([])}
