import { GoogleGenAI, Type } from "@google/genai";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const analyzeStoryboard = async (
  imageBase64: string,
  prompt: string,
  slots: { id: string; type: string }[]
): Promise<{ slotId: string; box: [number, number, number, number] }[]> => {
  const ai = getAIClient();

  const slotConstraints = slots.map(s => `"${s.type}" (ID: ${s.id})`).join(', ');

  const analysisPrompt = `
    Analyze this storyboard sketch and identify the regions for the following objects: ${slotConstraints}.
    Based on the image and the context: "${prompt}", find the most likely bounding boxes for these objects.

    Return the result as a JSON array of objects, each containing:
    - "slotId": the ID of the slot.
    - "box": [ymin, xmin, ymax, xmax] in normalized coordinates (0-1000).

    Example: [{"slotId": "A", "box": [100, 200, 500, 600]}]
    Only return the JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { inlineData: { data: imageBase64.split(',')[1], mimeType: 'image/png' } },
        { text: analysisPrompt }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              slotId: { type: Type.STRING },
              box: { 
                type: Type.ARRAY, 
                items: { type: Type.NUMBER },
                description: "[ymin, xmin, ymax, xmax]"
              }
            },
            required: ["slotId", "box"]
          }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Analysis Error:", error);
    return [];
  }
};

export const generateDirectorImage = async (
  baseImageBase64: string,
  maskImageBase64: string,
  prompt: string,
  references: { color: string, type: string, image: string }[]
): Promise<string[]> => {
  const ai = getAIClient();

  const referenceContext = references.map(ref => 
    `The area marked with ${ref.color} in the mask corresponds to ${ref.type}. Refer to the provided reference image for this object's design and identity.`
  ).join('\n');

  const finalPrompt = `
    TASK: Transform this storyboard sketch into a high-quality finished cinematic image.
    LOCATE: Maintain the composition, framing, and perspective of the original sketch.
    ASSIGN: 
    ${referenceContext}
    STORY CONTEXT: ${prompt}

    The output should be a single high-fidelity image that strictly follows these layout and design constraints.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: baseImageBase64.split(',')[1], mimeType: 'image/png' } },
          { inlineData: { data: maskImageBase64.split(',')[1], mimeType: 'image/png' } },
          ...references.map(ref => ({ inlineData: { data: ref.image.split(',')[1], mimeType: 'image/png' } })),
          { text: finalPrompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    const results: string[] = [];
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          results.push(`data:image/png;base64,${part.inlineData.data}`);
        }
      }
    }

    return results;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

