  { id: 'l1', name: '컬러 마스크 레이어', type: 'mask', visible: true, locked: false, active: true },
  { id: 'l2', name: '기본 스토리보드', type: 'base', visible: true, locked: true },
];

const App: React.FC = () => {
  const [projectInfo] = useState<ProjectInfo>({
    date: new Date().toLocaleDateString('ko-KR'),
    resolution: '1920 x 1080',
    description: '',
  });
  const [description, setDescription] = useState('');
  const [layers] = useState<StoryboardLayer[]>(INITIAL_LAYERS);
  const [slots, setSlots] = useState<ReferenceSlot[]>(INITIAL_SLOTS);
  const [activeColor, setActiveColor] = useState(INITIAL_SLOTS[0].color);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
  const [baseImage, setBaseImage] = useState<string>('https://picsum.photos/1920/1080?random=99');

  const [selectedStyleId, setSelectedStyleId] = useState<string>(STYLE_PRESETS[0].id);
  const [customStyleImage, setCustomStyleImage] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const bgImageRef = useRef<HTMLImageElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Setup canvas defaults
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = 20;
  }, []);

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.strokeStyle = activeColor;
    setIsDrawing(true);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const endDrawing = () => {
    setIsDrawing(false);
  };

  const handleAutoMask = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const results = await analyzeStoryboard(baseImage, description, slots);
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (!ctx || !canvas) return;

      // Draw detected regions
      results.forEach(res => {
        const slot = slots.find(s => s.id === res.slotId);
        if (slot) {
          const [ymin, xmin, ymax, xmax] = res.box;
          const w = xmax - xmin;
          const h = ymax - ymin;

          ctx.fillStyle = slot.color;
          ctx.globalAlpha = 0.5;
          ctx.beginPath();
          // Drawing a rounded rect or circle to look more "hand-painted" but precise
          ctx.arc(xmin + w/2, ymin + h/2, Math.max(w, h)/2, 0, Math.PI * 2);
          ctx.fill();
          ctx.globalAlpha = 1.0;
        }
      });
    } catch (err) {
      alert("자동 마스킹 중 오류가 발생했습니다.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleGenerate = async () => {
    if (isGenerating) return;
    setIsGenerating(true);

    try {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const maskData = canvas.toDataURL('image/png');
      const activeRefs = slots
