  const [currentTool, setCurrentTool] = useState<DrawingTool>('brush');

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
  const [baseImage, setBaseImage] = useState<string>('https://picsum.photos/1920/1080?random=99');

  const [selectedStyleId, setSelectedStyleId] = useState<string>(STYLE_PRESETS[0].id);
  const [customStyleImage, setCustomStyleImage] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const bgImageRef = useRef<HTMLImageElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Setup canvas defaults
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = 20;
  }, []);

  // Helper for flood fill
  const floodFill = (ctx: CanvasRenderingContext2D, startX: number, startY: number, fillColor: string) => {
    const canvasWidth = ctx.canvas.width;
    const canvasHeight = ctx.canvas.height;
    const imageData = ctx.getImageData(0, 0, canvasWidth, canvasHeight);
    const pixels = imageData.data;

    const getPixelPos = (x: number, y: number) => (y * canvasWidth + x) * 4;

    const hexToRgb = (hex: string) => {
      const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
      return result ? {
        r: parseInt(result[1], 16),
        g: parseInt(result[2], 16),
        b: parseInt(result[3], 16)
      } : { r: 0, g: 0, b: 0 };
    };

    const targetColor = hexToRgb(fillColor);
    const startPos = getPixelPos(Math.floor(startX), Math.floor(startY));
    const startR = pixels[startPos];
    const startG = pixels[startPos + 1];
    const startB = pixels[startPos + 2];
    const startA = pixels[startPos + 3];

    // Don't fill if the color is already the same
    if (startR === targetColor.r && startG === targetColor.g && startB === targetColor.b && startA === 255) return;

    const stack: [number, number][] = [[Math.floor(startX), Math.floor(startY)]];

    while (stack.length > 0) {
      const [x, y] = stack.pop()!;
      const pos = getPixelPos(x, y);

      if (pixels[pos] === startR && pixels[pos + 1] === startG && pixels[pos + 2] === startB && pixels[pos + 3] === startA) {
        pixels[pos] = targetColor.r;
        pixels[pos + 1] = targetColor.g;
        pixels[pos + 2] = targetColor.b;
        pixels[pos + 3] = 255;

        if (x > 0) stack.push([x - 1, y]);
        if (x < canvasWidth - 1) stack.push([x + 1, y]);
        if (y > 0) stack.push([x, y - 1]);
        if (y < canvasHeight - 1) stack.push([x, y + 1]);
      }
    }
    ctx.putImageData(imageData, 0, 0);
  };

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (currentTool === 'bucket') {
      floodFill(ctx, x, y, activeColor);
      return;
    }

    ctx.beginPath();
    ctx.moveTo(x, y);

    if (currentTool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out';
      ctx.lineWidth = 30;
    } else {
      ctx.globalCompositeOperation = 'source-over';
      ctx.strokeStyle = activeColor;
      ctx.lineWidth = 20;
    }

    setIsDrawing(true);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const endDrawing = () => {
    setIsDrawing(false);
  };

  const handleAutoMask = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const results = await analyzeStoryboard(baseImage, description, slots);
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (!ctx || !canvas) return;

      results.forEach(res => {
        const slot = slots.find(s => s.id === res.slotId);
        if (slot) {
          const [ymin, xmin, ymax, xmax] = res.box;
          const w = xmax - xmin;
          const h = ymax - ymin;

          ctx.globalCompositeOperation = 'source-over';
          ctx.fillStyle = slot.color;
          ctx.beginPath();
          ctx.arc(xmin + w/2, ymin + h/2, Math.max(w, h)/2, 0, Math.PI * 2);
          ctx.fill();
        }
      });
    } catch (err) {
      alert("자동 마스킹 중 오류가 발생했습니다.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleGenerate = async () => {
    if (isGenerating) return;
    setIsGenerating(true);

    try {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const maskData = canvas.toDataURL('image/png');
      const activeRefs = slots
        .filter(s => s.image)
        .map(s => ({ color: s.color, type: s.type, image: s.image! }));

      const currentStyle = STYLE_PRESETS.find(s => s.id === selectedStyleId);
      const stylePrompt = selectedStyleId === 'custom' && customStyleImage 
        ? "Follow the style of the custom style reference image provided." 
        : (currentStyle?.promptHint || "");

      const finalDescription = `${description}\n\nStyle Guide: ${stylePrompt}`;

      const results = await generateDirectorImage(baseImage, maskData, finalDescription, activeRefs);
      setGeneratedImages(results);
    } catch (err) {
      alert("이미지 생성에 실패했습니다. API 키나 네트워크 상태를 확인해주세요.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSlotUpload = (id: string) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setSlots(prev => prev.map(s => s.id === id ? { ...s, image: base64 } : s));
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const handleCustomStyleUpload = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setCustomStyleImage(base64);
          setSelectedStyleId('custom');
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const handleBaseUpload = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (re) => {
          const base64 = re.target?.result as string;
          setBaseImage(base64);
          setGeneratedImages([]); 
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const handleResetAll = () => {
    if (window.confirm("프로젝트를 초기화하시겠습니까? 모든 입력 내용이 삭제됩니다.")) {
      setDescription('');
      setGeneratedImages([]);
      setSlots(INITIAL_SLOTS);
      setActiveColor(INITIAL_SLOTS[0].color);
      setBaseImage('https://picsum.photos/1920/1080?random=' + Math.floor(Math.random() * 1000));
      setCustomStyleImage(null);
      setSelectedStyleId(STYLE_PRESETS[0].id);
      const ctx = canvasRef.current?.getContext('2d');
      ctx?.clearRect(0, 0, 1000, 562);
    }
  };

  const handleAddSlot = () => {
    const nextIndex = slots.length;
    const color = COLOR_PALETTE[nextIndex % COLOR_PALETTE.length];
    const newSlot: ReferenceSlot = {
      id: `S${nextIndex + 1}`,
      color: color,
      name: `슬롯 ${String.fromCharCode(65 + nextIndex)}`,
      type: '새 객체 타입'
    };
    setSlots([...slots, newSlot]);
    setActiveColor(color);
  };

  const removeSlot = (id: string) => {
    if (slots.length <= 1) return;
    setSlots(slots.filter(s => s.id !== id));
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#191919]">
      {/* Header */}
      <header className="flex items-center justify-between px-6 py-3 border-b border-[#3b3f54] bg-[#1c1d27]/80 backdrop-blur-md z-50">
        <div className="flex items-center gap-4">
          <div className="w-8 h-8 text-[#f7f7f7]">
            <svg fill="none" viewBox="0 0 48 48" xmlns="http://www.w3.org/2000/svg">
              <path d="M36.7273 44C33.9891 44 31.6043 39.8386 30.3636 33.69C29.123 39.8386 26.7382 44 24 44C21.2618 44 18.877 39.8386 17.6364 33.69C16.3957 39.8386 14.0109 44 11.2727 44C7.25611 44 4 35.0457 4 24C4 12.9543 7.25611 4 11.2727 4C14.0109 4 16.3957 8.16144 17.6364 14.31C18.877 8.16144 21.2618 4 24 4C26.7382 4 29.123 8.16144 30.3636 14.31C31.6043 8.16144 33.9891 4 36.7273 4C40.7439 4 44 12.9543 44 24C44 35.0457 40.7439 44 36.7273 44Z" fill="#2563eb" />
            </svg>
          </div>
          <div className="flex flex-col">
            <h2 className="text-white text-base font-bold leading-tight tracking-tight">Director-Centric AI</h2>
            <p className="text-[#9da1b9] text-xs font-normal">스토리보드 리마스터링 스튜디오</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
