            </button>
            <button className="flex items-center justify-center rounded-lg h-9 px-4 bg-[#2563eb] text-white text-sm font-bold transition-all hover:opacity-90">
              저장하기
            </button>
          </div>
          <div className="w-9 h-9 rounded-full border-2 border-blue-500/40 bg-cover" style={{ backgroundImage: `url('https://picsum.photos/100/100?u=1')` }} />
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">
        {/* Left Sidebar */}
        <aside className="w-80 border-r border-[#3b3f54] bg-[#191919] flex flex-col overflow-y-auto">
